-- Enrichment marathon batch: Ory, osem, osquery, OSSN, osTicket, OTOBO, OTRS, OTS

-- ── Ory ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Ory is an open-source identity and access management platform providing authentication, authorization, and fine-grained permissions infrastructure, available self-hosted or as the managed Ory Network cloud service.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (Developer tier); Production plan from $70/month$q$, starting_price),
  founded_year = COALESCE(2015, founded_year),
  company_size = COALESCE($q$11-50 employees$q$, company_size),
  headquarters = COALESCE($q$Munich, Germany$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Ory Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Ory review 2026: open-source identity, authentication and permissions infrastructure. Compare Ory Network pricing, features, pros, cons and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Ory is an open-source identity and access management (IAM) infrastructure company founded in 2015 by Aeneas Rekkas, Simon Kohl, and Thomas Aidan Curran, and headquartered in Munich, Germany, with a distributed team. What began as an open-source project grew into Ory Corp, which raised a Series A round of $22 million led by Insight Partners (bringing total funding to roughly $27.5 million) to build out its commercial managed offering, Ory Network. Ory's product suite is modular: Ory Kratos handles identity management, registration, login, multi-factor authentication and account recovery; Ory Hydra is a certified OAuth2 and OpenID Connect server; Ory Keto is a permissions and authorization engine modeled on Google's Zanzibar paper for fine-grained access control at scale; and Ory Oathkeeper acts as an identity and access proxy for zero-trust API gateways. All core components are open source under the Apache 2.0 license and can be self-hosted independently or combined, which differentiates Ory from monolithic, closed-source identity providers. For teams that do not want to operate this infrastructure themselves, Ory Network offers the same components as a fully managed cloud service. Pricing follows a freemium, usage-based model: a free Developer tier supports evaluation and prototyping with two development environments and community support; the Production plan starts at $70/month and covers one production project, three staging environments, and five development projects, with usage-based add-ons for machine-to-machine tokens and permission checks; the Growth plan starts at $9,350/year and adds multitenancy support, more environments, and lower per-unit usage pricing; and an Enterprise plan offers custom contracts for large organizations with compliance and support requirements. Ory targets software engineering and platform teams building consumer or B2B products that need login, SSO, MFA, and fine-grained authorization without building identity infrastructure from scratch, ranging from early-stage startups self-hosting the open-source components to scale-ups and enterprises on the managed Ory Network. Its main competitors include Auth0 (part of Okta), Keycloak (the dominant open-source alternative), FusionAuth, WorkOS, and cloud-native options like AWS Cognito, with Ory differentiating itself through its API-first, headless architecture, Zanzibar-style permissions engine, and open-source-first licensing that avoids vendor lock-in.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'f21e8c47-9727-46e1-8769-b1874bae4d03';

