-- ── osem ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$osem (Open Source Event Manager) is a free, self-hosted, Ruby on Rails event management platform built by the openSUSE community for running Free and Open Source Software conferences, from call-for-papers through scheduling.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE($q$Not publicly disclosed (openSUSE community project)$q$, company_size),
  headquarters = COALESCE($q$Not publicly disclosed (openSUSE community project)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$osem Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$osem review 2026: the free, open-source event manager built for FOSS conferences. Compare features, self-hosting setup and alternatives like Pretalx.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$osem, short for Open Source Event Manager, is a free and open-source event management platform maintained by the openSUSE community and built on Ruby on Rails. It is purpose-built for organizing Free and Open Source Software conferences rather than general commercial events, and its GitHub repository (openSUSE/osem) is MIT licensed with thousands of commits and hundreds of forks, reflecting a long-running community-maintained codebase. osem covers the full lifecycle of running a technical conference: organizers can open a call for papers, allow speakers to submit and edit proposals, classify and evaluate submissions through a review workflow, build and publish an event schedule and program page, manage speaker and volunteer information, and let attendees register and, in some configurations, purchase tickets. The platform has been used in production to run multiple editions of the openSUSE Conference and the ownCloud Conference, with organizers citing events with over 1,000 attendees and 500 paper submissions handled through the tool, demonstrating it works at real conference scale despite being a community-run project rather than a funded startup. There is no commercial company behind osem and no pricing tiers: it is entirely free, distributed as source code that organizers self-host, commonly via Docker and Docker Compose, on their own servers. Because it is a community project rather than a company, there is no official managed hosting or paid support tier, and organizations adopting it need someone comfortable running a Rails application in production. osem's target users are FOSS conference organizers, user-group and meetup organizers, and open-source foundations that want a purpose-built call-for-papers and scheduling tool rather than adapting a generic event-ticketing SaaS product to conference needs. Its closest alternatives include Pretalx (another open-source conference management tool popular in the Python and open-source event circuit), Sessionize, Indico (widely used in scientific and academic conference settings), and general-purpose commercial platforms like Eventbrite or Cvent, though those commercial tools lack osem's specific call-for-papers and program-review workflow built for volunteer-run technical conferences. osem's main differentiators are that it is free, fully open source, purpose-built for FOSS/tech conferences, and proven across multiple real-world community conferences over more than a decade of use.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'ff42786e-7806-4c57-bfcc-7884411de95a';

