-- ── osquery ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$osquery is an open-source, SQL-powered operating system instrumentation and monitoring framework, originally created by Facebook in 2014 and now governed by the vendor-neutral OSquery Foundation under the Linux Foundation.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2014, founded_year),
  company_size = COALESCE($q$Not publicly disclosed (governed by the OSquery Foundation, a Linux Foundation project)$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States (Linux Foundation)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$osquery Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$osquery review 2026: the open-source SQL framework for OS instrumentation and security monitoring. Features, governance, pricing and top alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$osquery is an open-source operating system instrumentation and monitoring framework that exposes an operating system's state, including processes, users, installed software, network connections, and hardware, as a set of relational database tables that can be queried with standard SQL. It was created by Facebook and publicly released as open source on October 29, 2014, initially supporting Linux and macOS, with full Windows support added in late 2016. The tool quickly saw adoption at major technology companies including Airbnb, Dropbox, Netflix, Etsy, Uber, and Palantir, who used it for security monitoring, incident response, and IT asset visibility at scale. Following community concerns that Facebook was not sufficiently investing in the project's long-term stewardship, Facebook and the Linux Foundation jointly announced in June 2019 the intent to form a new, vendor-neutral home for osquery; the OSquery Foundation was subsequently established under the Linux Foundation, governed by a Technical Steering Committee with engineers from companies including Meta, Trail of Bits, Google, Kolide, and Uptycs. osquery's core architecture centers on two tools: osqueryi, an interactive SQL shell for ad hoc queries and exploration, and osqueryd, a low-footprint daemon that schedules queries across a fleet of hosts and aggregates results into logs that flag state changes over time. The osquery schema spans more than 280 tables covering hardware, software, and OS events, and the project is dual-licensed under Apache 2.0 and GPLv2. Because osquery itself is a query engine rather than a full fleet-management platform, organizations typically pair it with a management layer; the most common are Fleet (an open-source osquery management platform) and Kolide (a commercial device-trust platform built on osquery), both of which add dashboards, deployment tooling, and alerting on top of the core project. osquery is entirely free and open source with no paid tiers of its own; commercial spending in this space goes toward these third-party fleet-management and endpoint-security layers rather than to osquery itself. Its target users are security engineers, detection and response teams, and IT operations teams needing deep, queryable visibility into endpoint and server state across large, heterogeneous fleets. Its closest points of comparison include Wazuh (an open-source SIEM/EDR platform), Fleet and Kolide (osquery-based fleet management), and commercial EDR products like CrowdStrike Falcon and SentinelOne, though osquery differentiates itself as a lightweight, vendor-neutral, SQL-first instrumentation layer rather than a full managed security product.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '2bf3de07-cc2a-49cd-8239-4d711fd37c68';

