-- ── OSSN ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Open Source Social Network (OSSN) is a free, self-hosted PHP script for building custom social networking websites and online communities, with an optional one-time-purchase premium version adding extra features.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (core script); Premium version $199 one-time$q$, starting_price),
  founded_year = COALESCE(2014, founded_year),
  company_size = COALESCE($q$Not publicly disclosed$q$, company_size),
  headquarters = COALESCE($q$Not publicly disclosed$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$OSSN Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$OSSN review 2026: the free, self-hosted PHP social network script. Compare core and premium features, one-time pricing and top alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$OSSN, or Open Source Social Network, is a free, self-hosted PHP script that lets developers and organizations build custom social networking websites, online communities, membership platforms, and private collaboration spaces without relying on a hosted third-party social media provider. The project was founded in 2014, with its GitHub organization maintained under opensource-socialnetwork, and it functions similarly in spirit to open-source Facebook alternatives, giving site owners full ownership of their codebase, branding, and user data. Out of the box, OSSN provides the core building blocks of a social network: user profiles, chronological timelines, groups, private messaging, photo albums, real-time likes and comments, notifications, and basic content sharing, all built on a hooks-and-events architecture that lets developers extend functionality with custom plugins and themes without modifying core files. Because it is self-hosted PHP software, site owners install it on their own server or hosting provider (it is also distributed through marketplaces like DigitalOcean's one-click app catalog and AWS Marketplace), giving them full data sovereignty, no per-user licensing caps, and no dependency on a third-party platform that could change its terms of service or shut down. OSSN's pricing model is freemium in the loosest sense: the core script is entirely free and open source with no subscription fees, while a separate premium version is sold for a one-time fee of $199 (lifetime license) that adds features such as hashtags, native video support, polls, events, stories, and link previews, features increasingly expected on modern social platforms but not included in the free core. There is no recurring SaaS subscription for either tier. OSSN's target users are developers and small organizations building niche community sites, enterprise intranets, alumni or membership networks, and privacy-focused social platforms who want full control over their social network's code and data rather than building on a hosted network like Facebook Groups or Mighty Networks. Its closest alternatives include Mastodon and other ActivityPub-based federated social platforms, Elgg (another long-running open-source social networking framework), BuddyPress (a WordPress-based social networking plugin), and hosted community platforms like Mighty Networks or Circle, with OSSN differentiating itself through its low one-time cost for premium features, PHP-based simplicity for developers already familiar with that ecosystem, and its explicit positioning as a full self-hosted alternative to commercial hosted social networks.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'f05bad91-5d44-4ab8-bd64-a36e981b6349';

