-- ── osTicket ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$osTicket is a widely used open-source customer support ticketing system maintained by Enhancesoft, offering a free self-hosted edition alongside paid cloud-hosted and enterprise plans.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (open source); Cloud-hosted from $12/agent/month$q$, starting_price),
  founded_year = COALESCE(2003, founded_year),
  company_size = COALESCE($q$Not publicly disclosed$q$, company_size),
  headquarters = COALESCE($q$Alexandria, Louisiana, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$osTicket Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$osTicket review 2026: the free open-source help desk ticketing system. Compare self-hosted, cloud and enterprise pricing, features and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$osTicket is an open-source customer support ticketing system that has been in continuous development since 2003, making it one of the longest-running open-source help desk platforms still in active use. It is maintained today by Enhancesoft, a software company headquartered in Alexandria, Louisiana, with an additional office in Eldoret, Kenya. osTicket's core value proposition is a mature, GPL-licensed, self-hosted ticketing system that organizations can run entirely for free, distinguishing it from most modern SaaS help desk tools that require an ongoing per-agent subscription. The platform converts emails, web forms, and API requests into trackable support tickets, and includes customizable ticket filters and routing rules, service level agreement (SLA) and business-hours management, configurable help topics and custom forms, department and agent management, and a customer-facing self-service portal with knowledge base articles. Enhancesoft monetizes osTicket through two paid tiers layered on top of the free open-source core: a Cloud-Hosted plan starting at $12 per agent per month, which includes managed infrastructure, daily backups, uptime guarantees, and email/phone support, and an Enterprise or Virtual Appliance tier with custom, quote-based pricing for organizations that need full customization alongside managed hosting. There is also SupportSystem, Enhancesoft's separately branded managed cloud offering built on the same osTicket codebase. osTicket's combination of a genuinely free, unlimited self-hosted edition and low-cost cloud entry pricing has made it a long-standing default choice for small and medium-sized businesses, IT help desks, and nonprofit organizations that need reliable ticketing without the cost of enterprise service-desk software. Its primary competitors include Zendesk and Freshdesk (both SaaS-first, more expensive help desk platforms), Zammad (a more modern open-source alternative), and OTRS/OTOBO (open-source ticketing systems oriented more toward ITSM than pure customer support). osTicket differentiates itself through its two-decade track record, large existing installed base, and the fact that its self-hosted edition remains completely free with no artificial agent limits, unlike many competitors that gate core functionality behind a paywall.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'c6e21c1b-c4e0-486b-8501-88c1bbe7830a';

