-- ── OTOBO ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$OTOBO is a free, open-source IT service management and ticketing platform forked from OTRS Community Edition in 2019, developed and commercially supported by Rother OSS GmbH in Germany.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted, unlimited agents); commercial support custom-quoted$q$, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE($q$Not publicly disclosed$q$, company_size),
  headquarters = COALESCE($q$Leiblfing, Germany$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$German$q$]::text[],
  seo_title = COALESCE($q$OTOBO Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$OTOBO review 2026: the free, open-source OTRS fork for IT service management and ticketing. Compare features, support pricing and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$OTOBO is an open-source IT service management (ITSM) and ticketing platform created in 2019 as a fork of OTRS Community Edition, built specifically to keep a fully free, GPLv3-licensed successor alive after OTRS AG signaled it would move away from a fully open community edition. OTOBO is developed and commercially backed by Rother OSS GmbH, a German software company headquartered in Leiblfing, Germany, founded by Stefan Rother, who was OTRS GmbH's first employee back in 2004 before leaving to start Rother OSS in 2011. Because Stefan Rother had deep firsthand experience with the original OTRS codebase, OTOBO was positioned from its founding as a way to return to the open-source roots of the ticketing system while adding modern capabilities, including Docker-based deployment, migration tooling from OTRS, Znuny, and the discontinued Community Edition, and a distinguishing AI-powered ticket classification plugin that uses machine learning to automatically pre-sort incoming tickets by category and priority. Functionally, OTOBO covers the full range of classic IT service desk operations: ticket recording and management, SLAs and escalation management, a knowledge base and self-service customer portal, process management workflows, and automation through OTOBO's Generic Agent engine, ticket templates, and auto-responses. The core software is completely free to self-host under the GPL v3 license, with no per-agent licensing fees and no cap on the number of agents, which is OTOBO's central differentiator versus commercial ticketing vendors including its own ancestor, OTRS. Rother OSS generates revenue not from software licensing but from professional services: consulting, training, hosting, technical support, and custom feature development for organizations that want expert help running OTOBO, priced on a custom, quote-based basis rather than published per-agent rates. OTOBO's target users are IT service management teams, managed service providers, and organizations that previously ran OTRS Community Edition and needed a free, actively maintained successor after OTRS AG discontinued that edition in December 2020. Its closest competitors and alternatives are OTRS itself (the commercial, proprietary-licensed original now majority-owned by EasyVista), Znuny (another community fork of OTRS Community Edition), Zammad, and osTicket, with OTOBO differentiating itself through its unlimited free agent model, AI ticket classification, and direct lineage to the original OTRS engineering team via founder Stefan Rother.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '7ff507f8-cdb5-4501-a01f-b42875d7b2a8';

