-- ── OTRS ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$OTRS is a commercial IT and customer service management platform from Germany's OTRS AG, offering ticketing, ITSM, and security incident response tools, after its free Community Edition was discontinued in December 2020.$q$, short_description),
  pricing_model = COALESCE($q$Subscription$q$, pricing_model),
  starting_price = COALESCE($q$Business Edition from approximately $49/agent/month$q$, starting_price),
  founded_year = COALESCE(2001, founded_year),
  company_size = COALESCE($q$Not publicly disclosed$q$, company_size),
  headquarters = COALESCE($q$Oberursel, Germany$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$German$q$]::text[],
  seo_title = COALESCE($q$OTRS Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$OTRS review 2026: enterprise ticketing, ITSM and SOAR software from OTRS AG. Compare Business and Enterprise pricing, features and alternatives like OTOBO.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$OTRS began in 2001 as an open-source help desk ticketing project created by developer Martin Edenhofer, with the commercial entity OTRS GmbH established in 2003 and later restructured as the publicly traded OTRS AG in 2007, listed on the Frankfurt Stock Exchange's Basic Board. The company is headquartered in Oberursel, Germany, and operates subsidiaries across the United States, Mexico, Singapore, Hong Kong, Brazil, and Hungary. Originally released under the GPL, OTRS progressively shifted toward a proprietary commercial model: the OTRS Business Solution launched as a paid add-on in 2015, and by 2018 the company offered a proprietary managed OTRS product and OTRS On-Premise alongside a still-free Community Edition. That changed in December 2020, when OTRS AG discontinued support for the free Community Edition entirely, a decision that prompted community members to create open-source forks, most notably Znuny and OTOBO, to preserve a free alternative; the Wikimedia Foundation, for example, migrated off the discontinued Community Edition to Znuny in April 2021. Today OTRS is sold exclusively as commercial software across Business and Enterprise editions, covering ticket and case management, IT service management (ITSM) capabilities, security incident response and SOAR (security orchestration, automation and response) tooling, SLA and escalation management, reporting dashboards, and information security management system (ISMS) features aligned with standards like ISO 27001. Pricing is quote-based, though third-party estimates place the Business Edition starting around $49 per agent per month, with Enterprise Edition pricing custom-quoted for large, complex deployments; broader market estimates suggest total costs in the range of roughly $25 to $100 per agent per month depending on modules. In December 2024, French service management vendor EasyVista acquired a majority stake in OTRS AG, folding OTRS into a larger enterprise service management portfolio. OTRS targets large enterprises, security operations centers, and regulated organizations that need deep ITSM and incident-response functionality with vendor accountability and formal support contracts, distinguishing it from lighter-weight open-source helpdesk tools. Its primary competitors and alternatives include ServiceNow (the dominant enterprise ITSM platform), Freshservice, Jira Service Management, and its own open-source descendants OTOBO and Znuny, both of which continue development of the codebase OTRS itself abandoned as free software in 2020.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '47b3f39e-f481-4d52-be50-11d497bacb7b';

