-- ── OTS ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$OTS (One Time Secrets, hosted at ots.fyi) is a free, open-source, self-hosted tool for sharing sensitive text or files as self-destructing links, encrypting secrets with AES-256 in the browser before they reach the server.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE($q$Not publicly disclosed (independently maintained open-source project)$q$, company_size),
  headquarters = COALESCE($q$Not publicly disclosed$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$OTS Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$OTS (ots.fyi) review 2026: free, open-source, self-hosted one-time secret sharing with browser-side AES-256 encryption. Features, setup and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$OTS, short for One Time Secrets and publicly demoed at ots.fyi, is a free, open-source, self-hosted tool for sharing sensitive text such as passwords, API keys, or private notes as one-time, self-destructing links. It is developed and maintained by an individual open-source developer known as Luzifer, whose GitHub repository (Luzifer/ots) hosts the project under the Apache 2.0 license, distinguishing OTS from venture-backed commercial secret-sharing products since there is no company, funding round, or enterprise sales team behind it. The core technical design is what sets OTS apart: rather than sending a plaintext secret to a server for storage, the secret is encrypted client-side in the browser using symmetric 256-bit AES encryption before transmission, and the decryption password is embedded only in the URL fragment (the part after the # symbol), which browsers never send to the server. As a result, the server only ever sees ciphertext and does not have practical means to decrypt stored secrets, and once a secret has been read for the first time, it is immediately and permanently deleted from storage, preventing replay or later retrieval even by someone with server access. Beyond the web interface, OTS ships a command-line interface for creating and retrieving secrets programmatically, with configurable expiry times and the ability to attach files, making it usable in scripting and automation workflows as well as ad hoc sharing. For deployment, OTS is distributed as a Docker image (ghcr.io/luzifer/ots) and as standalone binaries, and it supports pluggable storage backends including in-memory storage for lightweight, ephemeral deployments and Redis for more durable, production-grade self-hosted instances; ots.fyi itself serves as the project's official public demo instance, free for anyone to use without registration. Because OTS has no company or funding behind it, there is no pricing model beyond 'free and self-hosted'; there are no paid tiers, enterprise contracts, or managed hosting options offered by the maintainer. OTS's target users are developers, sysadmins, and IT teams who need to share credentials or sensitive configuration values securely with colleagues or clients, as well as privacy-conscious individuals who want to avoid pasting secrets into email, Slack, or chat tools where they persist indefinitely. Its closest alternatives include Onetime Secret (onetimesecret.com and its open-source codebase, the most widely known product in this category and a likely namesake influence), PrivateBin (a similarly self-hosted, browser-encrypted pastebin-style tool), and Yopass, with OTS differentiating itself through its lightweight Go and Vue codebase, simple Docker-based self-hosting, and companion CLI tool for scripted secret sharing.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'c4d14d8f-274a-43ad-92f6-8e61529bc76c';

