INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f21e8c47-9727-46e1-8769-b1874bae4d03', $q$Ory Kratos identity management$q$, $q$Headless, API-first user registration, login, MFA, and account recovery.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f21e8c47-9727-46e1-8769-b1874bae4d03', $q$Ory Hydra OAuth2/OIDC server$q$, $q$Certified OAuth2 and OpenID Connect provider for building SSO and delegated authorization.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f21e8c47-9727-46e1-8769-b1874bae4d03', $q$Ory Keto permissions engine$q$, $q$Fine-grained, Zanzibar-inspired authorization for modeling complex permission relationships.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f21e8c47-9727-46e1-8769-b1874bae4d03', $q$Ory Oathkeeper access proxy$q$, $q$Identity and access proxy for enforcing authentication and authorization at the API gateway layer.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f21e8c47-9727-46e1-8769-b1874bae4d03', $q$Ory Network managed cloud$q$, $q$Fully managed hosting of the Ory stack for teams that do not want to self-host.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f21e8c47-9727-46e1-8769-b1874bae4d03', $q$Passwordless and social sign-on$q$, $q$Support for passkeys, magic links, and social login providers alongside traditional credentials.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f21e8c47-9727-46e1-8769-b1874bae4d03', $q$Multi-language SDKs$q$, $q$Client SDKs and API references for integrating Ory into apps across major programming languages and frameworks.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f21e8c47-9727-46e1-8769-b1874bae4d03', $q$Fully open-source core components under the permissive Apache 2.0 license$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f21e8c47-9727-46e1-8769-b1874bae4d03', $q$Modular architecture lets teams adopt only the pieces they need (identity, OAuth2, permissions, or gateway)$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f21e8c47-9727-46e1-8769-b1874bae4d03', $q$Zanzibar-style permissions engine (Keto) handles complex authorization models that many competitors lack$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f21e8c47-9727-46e1-8769-b1874bae4d03', $q$Both self-hosted and fully managed (Ory Network) deployment options available$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f21e8c47-9727-46e1-8769-b1874bae4d03', $q$API-first, headless design integrates cleanly into custom frontends and mobile apps$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f21e8c47-9727-46e1-8769-b1874bae4d03', $q$Self-hosting the full stack requires meaningful DevOps and identity domain expertise$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f21e8c47-9727-46e1-8769-b1874bae4d03', $q$Documentation and configuration can be complex for teams new to headless identity infrastructure$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f21e8c47-9727-46e1-8769-b1874bae4d03', $q$Usage-based pricing on Ory Network can grow significantly with active user and permission-check volume$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f21e8c47-9727-46e1-8769-b1874bae4d03', $q$Higher-tier features like multitenancy are gated behind the more expensive Growth and Enterprise plans$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f21e8c47-9727-46e1-8769-b1874bae4d03', $q$Smaller ecosystem and community size compared to more established players like Keycloak$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f21e8c47-9727-46e1-8769-b1874bae4d03', $q$Is Ory free to use?$q$, $q$Yes. Ory's core components (Kratos, Hydra, Keto, Oathkeeper) are open source under the Apache 2.0 license and free to self-host. The managed Ory Network also offers a free Developer tier for evaluation and prototyping.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f21e8c47-9727-46e1-8769-b1874bae4d03', $q$What is Ory Kratos?$q$, $q$Ory Kratos is Ory's identity management component, handling user registration, login, multi-factor authentication, and account recovery through a headless, API-first architecture.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f21e8c47-9727-46e1-8769-b1874bae4d03', $q$What is the difference between self-hosting Ory and using Ory Network?$q$, $q$Self-hosting means running the open-source Ory components (Kratos, Hydra, Keto, Oathkeeper) on your own infrastructure for free. Ory Network is Ory's fully managed cloud version of the same components, priced on a freemium, usage-based model starting at $70/month for production use.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f21e8c47-9727-46e1-8769-b1874bae4d03', $q$How much does Ory Network cost?$q$, $q$Ory Network has a free Developer tier, a Production plan starting at $70/month, a Growth plan starting at $9,350/year, and custom Enterprise pricing, with usage-based charges for items like machine-to-machine tokens and permission checks.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f21e8c47-9727-46e1-8769-b1874bae4d03', $q$Does Ory support passwordless authentication?$q$, $q$Yes, Ory supports passwordless and passkey-based authentication, along with social sign-on and traditional password and multi-factor authentication flows.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f21e8c47-9727-46e1-8769-b1874bae4d03', $q$What is Ory Keto used for?$q$, $q$Ory Keto is a fine-grained permissions and authorization engine modeled on Google's Zanzibar paper, used to model complex access-control relationships between users, groups, and resources.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f21e8c47-9727-46e1-8769-b1874bae4d03', $q$Who are Ory's main competitors?$q$, $q$Ory's main competitors include Auth0 (owned by Okta), Keycloak, FusionAuth, WorkOS, and AWS Cognito.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f21e8c47-9727-46e1-8769-b1874bae4d03', $q$Is Ory suitable for enterprise use?$q$, $q$Yes, Ory offers a custom Enterprise plan on Ory Network with dedicated support and compliance features, in addition to its open-source components that enterprises can self-host under their own security controls.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f21e8c47-9727-46e1-8769-b1874bae4d03', $q$Consumer app authentication$q$, $q$Product teams use Ory Kratos and Hydra to add login, MFA, and social sign-on to consumer-facing web and mobile apps without building identity infrastructure in-house.$q$, $q$Product and engineering teams at startups and scale-ups$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f21e8c47-9727-46e1-8769-b1874bae4d03', $q$B2B SaaS authorization and multitenancy$q$, $q$B2B SaaS companies use Ory Keto's Zanzibar-style permissions engine to model complex, multi-tenant role and resource permissions.$q$, $q$B2B SaaS platform engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f21e8c47-9727-46e1-8769-b1874bae4d03', $q$Zero-trust API access control$q$, $q$Platform and security teams deploy Ory Oathkeeper as an identity-aware proxy in front of internal and external APIs to enforce zero-trust access policies.$q$, $q$Security and platform engineering teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f21e8c47-9727-46e1-8769-b1874bae4d03', $q$Developer$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["2 development environments","Community support","Full access to core identity and permissions APIs for evaluation"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f21e8c47-9727-46e1-8769-b1874bae4d03', $q$Production$q$, $q$$70/month + usage$q$, $q$Monthly$q$, NULL, $q$["1 production project","3 staging environments","5 development projects","Usage-based machine-to-machine tokens and permission checks"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f21e8c47-9727-46e1-8769-b1874bae4d03', $q$Growth$q$, $q$$9,350/year + usage$q$, $q$Annual$q$, NULL, $q$["2 production projects","5 staging environments","20 development environments","Multitenancy support","Lower usage-based unit pricing"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f21e8c47-9727-46e1-8769-b1874bae4d03', $q$Enterprise$q$, $q$Custom$q$, $q$Annual$q$, NULL, $q$["Custom SLAs","Dedicated support","Advanced compliance and security options"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f21e8c47-9727-46e1-8769-b1874bae4d03', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Ory is an open-source identity and access management platform built around a modular set of components: Kratos for identity, Hydra for OAuth2/OIDC, Keto for permissions, and Oathkeeper for API access control. Each piece can be run independently, self-hosted, or consumed together through the managed Ory Network cloud service.$q$, $q$Founded in 2015 in Munich, Germany, Ory grew from an open-source project into a venture-backed company after raising a $22 million Series A led by Insight Partners. The company positions itself as infrastructure for developers who want authentication and authorization without building it from scratch or locking into a closed-source vendor.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f21e8c47-9727-46e1-8769-b1874bae4d03', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Ory Kratos provides self-service registration, login, account recovery, and multi-factor and passwordless authentication as headless, API-first identity management. Ory Hydra is a certified OAuth2 and OpenID Connect server for building SSO and API authorization flows.$q$, $q$Ory Keto implements a Zanzibar-inspired permissions engine for fine-grained authorization at scale, and Ory Oathkeeper acts as an identity-aware proxy for zero-trust API gateways. All four components are open source under Apache 2.0 and can be deployed self-hosted or via the managed Ory Network.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f21e8c47-9727-46e1-8769-b1874bae4d03', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Ory's free Developer tier is intended for evaluation and prototyping, with two development environments and community-only support, and the open-source components can always be self-hosted for free.$q$, $q$Paid Ory Network plans scale from Production at $70/month (one production project, usage-based token and permission-check pricing) to Growth at $9,350/year for larger, multi-tenant deployments, up to custom Enterprise pricing for large organizations with compliance needs.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f21e8c47-9727-46e1-8769-b1874bae4d03', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff42786e-7806-4c57-bfcc-7884411de95a', $q$Call for papers management$q$, $q$Open a public call for papers and let speakers submit, edit, and track proposals for a conference.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff42786e-7806-4c57-bfcc-7884411de95a', $q$Submission review and classification$q$, $q$Organizers evaluate, score, and classify incoming paper submissions through a structured review workflow.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff42786e-7806-4c57-bfcc-7884411de95a', $q$Event schedule and program builder$q$, $q$Build and publish a detailed conference schedule with session, room, and time information.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff42786e-7806-4c57-bfcc-7884411de95a', $q$Event website and splash pages$q$, $q$Generate a public-facing event page directly from the platform for marketing and information.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff42786e-7806-4c57-bfcc-7884411de95a', $q$Attendee registration$q$, $q$Let visitors register for the event, with support for ticketing in some deployments.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff42786e-7806-4c57-bfcc-7884411de95a', $q$Speaker and volunteer management$q$, $q$Track speaker details and coordinate volunteers involved in running the conference.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff42786e-7806-4c57-bfcc-7884411de95a', $q$Self-hosted Docker deployment$q$, $q$Deploy osem on your own infrastructure using Docker and Docker Compose.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ff42786e-7806-4c57-bfcc-7884411de95a', $q$Completely free and open source with the MIT license$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ff42786e-7806-4c57-bfcc-7884411de95a', $q$Purpose-built for the specific workflow of FOSS and technical conferences$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ff42786e-7806-4c57-bfcc-7884411de95a', $q$Proven in production across multiple real conferences with over 1,000 attendees$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ff42786e-7806-4c57-bfcc-7884411de95a', $q$Long-running, community-maintained project with an active GitHub repository$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ff42786e-7806-4c57-bfcc-7884411de95a', $q$Full control over data and hosting since it is entirely self-hosted$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ff42786e-7806-4c57-bfcc-7884411de95a', $q$Requires self-hosting and Ruby on Rails operational knowledge, unlike turnkey SaaS event tools$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ff42786e-7806-4c57-bfcc-7884411de95a', $q$No official managed hosting or paid support tier available$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ff42786e-7806-4c57-bfcc-7884411de95a', $q$User interface is more utilitarian than modern commercial event platforms$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ff42786e-7806-4c57-bfcc-7884411de95a', $q$Smaller contributor community than mainstream event-management SaaS products$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ff42786e-7806-4c57-bfcc-7884411de95a', $q$Best suited to technical/FOSS conferences rather than general commercial events$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ff42786e-7806-4c57-bfcc-7884411de95a', $q$Is osem free to use?$q$, $q$Yes, osem is entirely free and open source under the MIT license, maintained by the openSUSE community with no paid tiers or licensing fees.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ff42786e-7806-4c57-bfcc-7884411de95a', $q$Who maintains osem?$q$, $q$osem is maintained by the openSUSE community as an open-source project on GitHub, rather than by a commercial company.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ff42786e-7806-4c57-bfcc-7884411de95a', $q$What is osem used for?$q$, $q$osem is used to run Free and Open Source Software conferences, covering call-for-papers submission, review, scheduling, event websites, and attendee registration.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ff42786e-7806-4c57-bfcc-7884411de95a', $q$Do I need to self-host osem?$q$, $q$Yes, osem is a self-hosted platform. Organizers deploy it on their own servers, commonly using Docker, since there is no official managed cloud version.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ff42786e-7806-4c57-bfcc-7884411de95a', $q$What technology is osem built with?$q$, $q$osem is built primarily with Ruby on Rails, with additional use of Haml for templating and Docker for deployment.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ff42786e-7806-4c57-bfcc-7884411de95a', $q$Which conferences have used osem?$q$, $q$osem has powered multiple editions of the openSUSE Conference and the ownCloud Conference, among other Free and Open Source Software community events.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ff42786e-7806-4c57-bfcc-7884411de95a', $q$What are alternatives to osem?$q$, $q$Alternatives include Pretalx, Indico, Sessionize, and general-purpose commercial event platforms like Eventbrite, though those lack osem's conference-specific call-for-papers review workflow.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ff42786e-7806-4c57-bfcc-7884411de95a', $q$FOSS conference call for papers$q$, $q$Conference organizers use osem to open a public call for papers, collect speaker submissions, and run a structured review process.$q$, $q$Open-source conference organizers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ff42786e-7806-4c57-bfcc-7884411de95a', $q$Technical conference scheduling$q$, $q$Organizers build and publish multi-track conference schedules and session details directly through osem's program builder.$q$, $q$Conference program committees$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ff42786e-7806-4c57-bfcc-7884411de95a', $q$Community event registration$q$, $q$User groups and open-source foundations use osem to manage attendee registration for community-run technical events.$q$, $q$Open-source foundations and user groups$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ff42786e-7806-4c57-bfcc-7884411de95a', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Call for papers management","Submission review workflow","Event scheduling and program builder","Attendee registration","Self-hosted via Docker"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ff42786e-7806-4c57-bfcc-7884411de95a', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$osem, or Open Source Event Manager, is a free, open-source event management tool maintained by the openSUSE community and built on Ruby on Rails. It was created specifically to handle the workflow of running Free and Open Source Software conferences, rather than general commercial events.$q$, $q$The tool has been used to run multiple editions of the openSUSE Conference and the ownCloud Conference, handling events with over 1,000 attendees and 500 paper submissions, and remains actively developed as a community open-source project on GitHub under the MIT license.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ff42786e-7806-4c57-bfcc-7884411de95a', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$osem supports the full conference lifecycle: opening a call for papers, collecting and reviewing speaker submissions, building and publishing an event schedule, and managing registration. Organizers can create a public event website and splash page directly from the platform.$q$, $q$Because it targets volunteer-run technical conferences specifically, osem includes program-review and classification workflows for evaluating paper submissions that many general-purpose event platforms lack, along with speaker and volunteer coordination tools.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ff42786e-7806-4c57-bfcc-7884411de95a', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$osem is completely free and open source with no paid tiers, since it is maintained by the openSUSE community rather than a commercial company.$q$, $q$Organizers self-host osem on their own infrastructure, typically using Docker, and there is no official managed hosting or paid support offering; the only cost is the organizer's own server hosting.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ff42786e-7806-4c57-bfcc-7884411de95a', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ff42786e-7806-4c57-bfcc-7884411de95a', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2bf3de07-cc2a-49cd-8239-4d711fd37c68', $q$SQL-based system querying$q$, $q$Query operating system state, such as processes, users, and network connections, using standard SQL through the osqueryi shell.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2bf3de07-cc2a-49cd-8239-4d711fd37c68', $q$osqueryd scheduled monitoring daemon$q$, $q$A low-footprint daemon that runs scheduled queries across a fleet and logs state changes over time.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2bf3de07-cc2a-49cd-8239-4d711fd37c68', $q$280+ table schema$q$, $q$A relational schema covering hardware, software, and operating system events across supported platforms.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2bf3de07-cc2a-49cd-8239-4d711fd37c68', $q$Cross-platform support$q$, $q$Runs on Windows, macOS, and major Linux distributions including Ubuntu and CentOS.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2bf3de07-cc2a-49cd-8239-4d711fd37c68', $q$Extensible via custom tables$q$, $q$Teams can build custom tables and extensions to expose additional system or application data.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2bf3de07-cc2a-49cd-8239-4d711fd37c68', $q$Vendor-neutral open governance$q$, $q$Governed by the OSquery Foundation under the Linux Foundation with a multi-company Technical Steering Committee.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2bf3de07-cc2a-49cd-8239-4d711fd37c68', $q$Dual open-source licensing$q$, $q$Distributed under both Apache 2.0 and GPLv2 licenses.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2bf3de07-cc2a-49cd-8239-4d711fd37c68', $q$Completely free and open source with no licensing costs$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2bf3de07-cc2a-49cd-8239-4d711fd37c68', $q$Powerful SQL abstraction makes complex endpoint investigation queries accessible to teams already comfortable with SQL$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2bf3de07-cc2a-49cd-8239-4d711fd37c68', $q$Cross-platform support across Windows, macOS, and Linux$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2bf3de07-cc2a-49cd-8239-4d711fd37c68', $q$Vendor-neutral governance under the Linux Foundation reduces single-company risk$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2bf3de07-cc2a-49cd-8239-4d711fd37c68', $q$Proven at scale by major technology companies including Airbnb, Netflix, and Uber$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2bf3de07-cc2a-49cd-8239-4d711fd37c68', $q$Extensible schema supports custom tables for organization-specific data$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2bf3de07-cc2a-49cd-8239-4d711fd37c68', $q$No built-in fleet management UI, dashboards, or alerting out of the box$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2bf3de07-cc2a-49cd-8239-4d711fd37c68', $q$Requires pairing with a separate tool like Fleet or Kolide for practical fleet-wide deployment$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2bf3de07-cc2a-49cd-8239-4d711fd37c68', $q$Writing effective, performant queries at scale requires a learning curve$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2bf3de07-cc2a-49cd-8239-4d711fd37c68', $q$Log pipeline and alerting infrastructure must be built or integrated separately$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2bf3de07-cc2a-49cd-8239-4d711fd37c68', $q$Community development pace can vary since it depends on volunteer and sponsoring-company contributions$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2bf3de07-cc2a-49cd-8239-4d711fd37c68', $q$Is osquery free?$q$, $q$Yes, osquery is completely free and open source, dual-licensed under Apache 2.0 and GPLv2, with no paid tiers for the core project itself.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2bf3de07-cc2a-49cd-8239-4d711fd37c68', $q$Who created osquery?$q$, $q$osquery was created by Facebook and publicly released as open source on October 29, 2014. Governance later transferred to the vendor-neutral OSquery Foundation under the Linux Foundation in 2019.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2bf3de07-cc2a-49cd-8239-4d711fd37c68', $q$What is the difference between osqueryi and osqueryd?$q$, $q$osqueryi is an interactive SQL shell for running ad hoc queries against system state, while osqueryd is a background daemon that runs scheduled queries across a fleet of machines and logs changes over time.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2bf3de07-cc2a-49cd-8239-4d711fd37c68', $q$Does osquery include a management dashboard?$q$, $q$No, osquery itself is a query engine and daemon without a built-in fleet dashboard. Most organizations pair it with a separate tool like Fleet or Kolide for fleet-wide management and alerting.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2bf3de07-cc2a-49cd-8239-4d711fd37c68', $q$What platforms does osquery support?$q$, $q$osquery supports Windows, macOS, and major Linux distributions such as Ubuntu and CentOS, with a schema of over 280 tables covering hardware, software, and OS events.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2bf3de07-cc2a-49cd-8239-4d711fd37c68', $q$Who governs osquery today?$q$, $q$osquery is governed by the OSquery Foundation, a project under the Linux Foundation, directed by a Technical Steering Committee with members from companies including Meta, Trail of Bits, Google, and Kolide.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2bf3de07-cc2a-49cd-8239-4d711fd37c68', $q$What companies use osquery?$q$, $q$osquery has been used in production by companies including Airbnb, Dropbox, Netflix, Etsy, Uber, and Palantir for security monitoring and infrastructure visibility.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2bf3de07-cc2a-49cd-8239-4d711fd37c68', $q$What are alternatives to osquery?$q$, $q$Common alternatives and complements include Wazuh, Fleet, Kolide, and commercial EDR platforms like CrowdStrike Falcon and SentinelOne.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2bf3de07-cc2a-49cd-8239-4d711fd37c68', $q$Security incident investigation$q$, $q$Security teams use osquery's SQL interface to investigate endpoint compromises by querying process, network, and file system state across affected hosts.$q$, $q$Security engineers and incident responders$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2bf3de07-cc2a-49cd-8239-4d711fd37c68', $q$Fleet-wide compliance monitoring$q$, $q$IT and security teams schedule osqueryd queries across their device fleet to continuously monitor for configuration drift and compliance violations.$q$, $q$IT operations and compliance teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2bf3de07-cc2a-49cd-8239-4d711fd37c68', $q$Infrastructure visibility at scale$q$, $q$DevOps teams at large technology companies use osquery to gain queryable visibility into server and workstation state across thousands of hosts.$q$, $q$DevOps and platform engineering teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2bf3de07-cc2a-49cd-8239-4d711fd37c68', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["osqueryi interactive SQL shell","osqueryd scheduled monitoring daemon","280+ table schema","Cross-platform support (Windows, macOS, Linux)","Custom table extensions"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2bf3de07-cc2a-49cd-8239-4d711fd37c68', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$osquery is an open-source framework that turns an operating system into a queryable relational database, letting security and IT teams run SQL queries against low-level system state such as running processes, installed packages, users, and network connections. It was originally built and open-sourced by Facebook in 2014.$q$, $q$In 2019, governance of the project moved from Facebook to the newly formed OSquery Foundation under the Linux Foundation, making it a vendor-neutral, community-governed project overseen by a Technical Steering Committee with representatives from companies including Meta, Trail of Bits, Google, and Kolide.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2bf3de07-cc2a-49cd-8239-4d711fd37c68', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$osquery ships with two primary tools: osqueryi, an interactive SQL shell for exploring system state, and osqueryd, a lightweight daemon that runs scheduled queries across a fleet of machines and logs state changes over time. Its schema exposes more than 280 tables covering hardware, software, and OS-level events.$q$, $q$The project supports Windows, macOS, and major Linux distributions, and is extensible through custom tables and extensions. Because osquery itself does not include a management dashboard, it is commonly deployed alongside a fleet-management layer such as Fleet or Kolide.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2bf3de07-cc2a-49cd-8239-4d711fd37c68', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$osquery itself is completely free and open source, dual-licensed under Apache 2.0 and GPLv2, with no paid tiers, subscriptions, or licensing fees for the core project.$q$, $q$Organizations that want a management UI, alerting, or fleet deployment tooling on top of osquery typically adopt a separate product, such as the open-source Fleet platform or the commercial Kolide device-trust platform, which carry their own independent pricing.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('2bf3de07-cc2a-49cd-8239-4d711fd37c68', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f05bad91-5d44-4ab8-bd64-a36e981b6349', $q$User profiles and timelines$q$, $q$Chronological user profiles and activity timelines form the core of the social experience.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f05bad91-5d44-4ab8-bd64-a36e981b6349', $q$Groups, forums, and messaging$q$, $q$Members can create niche groups, participate in forums, and exchange private messages.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f05bad91-5d44-4ab8-bd64-a36e981b6349', $q$Photo albums and media sharing$q$, $q$Users can upload and share photo albums with likes and comments on shared content.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f05bad91-5d44-4ab8-bd64-a36e981b6349', $q$Hooks-and-events plugin architecture$q$, $q$Developers extend functionality with custom plugins and themes without editing core files.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f05bad91-5d44-4ab8-bd64-a36e981b6349', $q$Custom themes and responsive design$q$, $q$Site owners can restyle the platform with custom themes while retaining mobile responsiveness.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f05bad91-5d44-4ab8-bd64-a36e981b6349', $q$Full self-hosted data ownership$q$, $q$All user data and content stay on infrastructure the site owner controls, with no third-party platform dependency.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f05bad91-5d44-4ab8-bd64-a36e981b6349', $q$Premium modern social features$q$, $q$Paid add-on unlocking hashtags, video, polls, events, stories, and link previews for a one-time fee.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f05bad91-5d44-4ab8-bd64-a36e981b6349', $q$Core platform is completely free and open source with no recurring subscription$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f05bad91-5d44-4ab8-bd64-a36e981b6349', $q$Full data ownership and control since the site is self-hosted$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f05bad91-5d44-4ab8-bd64-a36e981b6349', $q$One-time $199 fee for premium features avoids ongoing SaaS costs$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f05bad91-5d44-4ab8-bd64-a36e981b6349', $q$Extensible hooks-and-events architecture supports custom plugins and themes$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f05bad91-5d44-4ab8-bd64-a36e981b6349', $q$No artificial user or member limits imposed by the platform itself$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f05bad91-5d44-4ab8-bd64-a36e981b6349', $q$Available as a one-click install via marketplaces like DigitalOcean and AWS$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f05bad91-5d44-4ab8-bd64-a36e981b6349', $q$Requires self-managed PHP hosting, server maintenance, and security updates$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f05bad91-5d44-4ab8-bd64-a36e981b6349', $q$Modern social features like hashtags, video, and stories require the paid premium version$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f05bad91-5d44-4ab8-bd64-a36e981b6349', $q$User interface is generally considered dated compared to modern SaaS community platforms$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f05bad91-5d44-4ab8-bd64-a36e981b6349', $q$Smaller developer and plugin ecosystem than WordPress-based social alternatives like BuddyPress$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f05bad91-5d44-4ab8-bd64-a36e981b6349', $q$Company/founder information behind the project is not prominently publicly disclosed$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f05bad91-5d44-4ab8-bd64-a36e981b6349', $q$Is OSSN free to use?$q$, $q$Yes, the core OSSN script is free and open source with no subscription fees. A separate premium version is available for a one-time $199 lifetime fee that adds features like hashtags, video, and stories.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f05bad91-5d44-4ab8-bd64-a36e981b6349', $q$Do I need to self-host OSSN?$q$, $q$Yes, OSSN is self-hosted PHP software. You install it on your own server or hosting provider, though it is also available as a one-click app on marketplaces like DigitalOcean and AWS.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f05bad91-5d44-4ab8-bd64-a36e981b6349', $q$What features are in the OSSN premium version?$q$, $q$The $199 one-time premium version adds hashtags, native video support, polls, events, stories, and link previews on top of the free core platform.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f05bad91-5d44-4ab8-bd64-a36e981b6349', $q$What does OSSN include for free?$q$, $q$The free core includes user profiles, timelines, groups, forums, private messaging, photo albums, likes, comments, and notifications.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f05bad91-5d44-4ab8-bd64-a36e981b6349', $q$Can I customize OSSN with plugins?$q$, $q$Yes, OSSN uses a hooks-and-events architecture that lets developers add custom plugins and themes without modifying the platform's core files.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f05bad91-5d44-4ab8-bd64-a36e981b6349', $q$Who owns the data on an OSSN site?$q$, $q$Because OSSN is self-hosted, the site owner fully owns the codebase, branding, and all user data, with no dependency on a third-party social media provider.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f05bad91-5d44-4ab8-bd64-a36e981b6349', $q$What are alternatives to OSSN?$q$, $q$Alternatives include Elgg, BuddyPress (for WordPress sites), Mastodon and other ActivityPub-based platforms, and hosted community platforms like Mighty Networks or Circle.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f05bad91-5d44-4ab8-bd64-a36e981b6349', $q$Niche community website$q$, $q$Organizations build a dedicated social platform around a specific interest or industry rather than relying on a generic hosted social network.$q$, $q$Niche community builders and hobbyist site owners$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f05bad91-5d44-4ab8-bd64-a36e981b6349', $q$Enterprise intranet and internal collaboration$q$, $q$Companies deploy a self-hosted OSSN instance as a private social intranet for internal employee communication and collaboration.$q$, $q$Enterprise IT and internal communications teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f05bad91-5d44-4ab8-bd64-a36e981b6349', $q$Alumni and membership networks$q$, $q$Schools, universities, and membership organizations use OSSN to run a private, self-hosted network for alumni or paying members.$q$, $q$Educational institutions and membership organizations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f05bad91-5d44-4ab8-bd64-a36e981b6349', $q$Open Source Core$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["User profiles and timelines","Groups and forums","Private messaging","Photo albums","Custom themes and plugins"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f05bad91-5d44-4ab8-bd64-a36e981b6349', $q$Premium$q$, $q$$199 one-time$q$, $q$One-time (lifetime)$q$, NULL, $q$["Everything in Open Source Core","Hashtags","Video support","Polls","Events","Stories","Link previews"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f05bad91-5d44-4ab8-bd64-a36e981b6349', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$OSSN, or Open Source Social Network, is a free, self-hosted PHP script for building custom social networking websites and online communities. Founded in 2014, the project provides the core infrastructure of a social platform, including profiles, timelines, groups, and messaging, as free and open-source software that site owners install and control themselves.$q$, $q$Because it is self-hosted, OSSN gives organizations full ownership of their codebase, branding, and user data, avoiding the vendor lock-in and data-control concerns that come with building a community on a third-party hosted social network.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f05bad91-5d44-4ab8-bd64-a36e981b6349', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The free core includes user profiles, chronological timelines, groups, forums, private messaging, photo albums, real-time likes and comments, and notifications, all built on an extensible hooks-and-events architecture that supports custom themes and plugins without modifying core files.$q$, $q$A separate premium version, sold as a one-time $199 lifetime purchase, adds newer social features including hashtags, video support, polls, events, stories, and link previews, extending the free core with capabilities common on modern commercial social platforms.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f05bad91-5d44-4ab8-bd64-a36e981b6349', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$OSSN's core script is completely free and open source, with no subscription fees or artificial user limits, and can be self-hosted on any PHP-compatible server or deployed via one-click marketplace listings on platforms like DigitalOcean.$q$, $q$Organizations wanting additional modern social features can purchase the premium version for a one-time fee of $199, which unlocks lifetime access to hashtags, video, polls, events, stories, and link previews on top of the free core.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f05bad91-5d44-4ab8-bd64-a36e981b6349', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f05bad91-5d44-4ab8-bd64-a36e981b6349', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6e21c1b-c4e0-486b-8501-88c1bbe7830a', $q$Multi-channel ticket intake$q$, $q$Automatically converts emails, web forms, and API requests into trackable support tickets.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6e21c1b-c4e0-486b-8501-88c1bbe7830a', $q$Custom ticket filters and routing$q$, $q$Rules-based routing sends incoming tickets to the correct department or agent automatically.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6e21c1b-c4e0-486b-8501-88c1bbe7830a', $q$SLA and business-hours management$q$, $q$Define business hours and response-time policies to enforce service level agreements.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6e21c1b-c4e0-486b-8501-88c1bbe7830a', $q$Customer self-service portal$q$, $q$A knowledge base and ticket-tracking portal lets customers find answers and check ticket status without contacting an agent.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6e21c1b-c4e0-486b-8501-88c1bbe7830a', $q$Custom help topics and forms$q$, $q$Configure help topics and custom fields to better categorize and prioritize incoming requests.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6e21c1b-c4e0-486b-8501-88c1bbe7830a', $q$Department and agent management$q$, $q$Organize support staff into departments with role-based permissions and assignment rules.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6e21c1b-c4e0-486b-8501-88c1bbe7830a', $q$Cloud-hosted managed option$q$, $q$A paid, fully managed hosting tier removes the need to run and maintain your own server infrastructure.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c6e21c1b-c4e0-486b-8501-88c1bbe7830a', $q$Self-hosted core edition is completely free with no per-agent licensing cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c6e21c1b-c4e0-486b-8501-88c1bbe7830a', $q$Mature, battle-tested platform with over two decades of continuous development$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c6e21c1b-c4e0-486b-8501-88c1bbe7830a', $q$Large community, documentation base, and plugin ecosystem$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c6e21c1b-c4e0-486b-8501-88c1bbe7830a', $q$Flexible deployment as self-hosted, cloud-hosted, or enterprise virtual appliance$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c6e21c1b-c4e0-486b-8501-88c1bbe7830a', $q$Granular SLA, routing, and department management for structured support teams$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c6e21c1b-c4e0-486b-8501-88c1bbe7830a', $q$Affordable cloud entry price relative to major SaaS help desk competitors$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c6e21c1b-c4e0-486b-8501-88c1bbe7830a', $q$Self-hosted edition's interface feels dated compared to modern SaaS help desk tools$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c6e21c1b-c4e0-486b-8501-88c1bbe7830a', $q$Cloud-Hosted plan is less customizable than the self-hosted edition$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c6e21c1b-c4e0-486b-8501-88c1bbe7830a', $q$Advanced customization requires the higher-priced Enterprise/Virtual Appliance tier$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c6e21c1b-c4e0-486b-8501-88c1bbe7830a', $q$Self-hosting requires ongoing server maintenance, updates, and security patching$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c6e21c1b-c4e0-486b-8501-88c1bbe7830a', $q$Built-in reporting and analytics are more limited than newer competitors like Zendesk$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c6e21c1b-c4e0-486b-8501-88c1bbe7830a', $q$Is osTicket really free?$q$, $q$Yes. The self-hosted, open-source edition of osTicket is completely free to download and use, with no per-agent licensing fees. Paid Cloud-Hosted and Enterprise tiers are available for organizations that want managed infrastructure and support.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c6e21c1b-c4e0-486b-8501-88c1bbe7830a', $q$How much does osTicket Cloud cost?$q$, $q$osTicket's Cloud-Hosted plan starts at $12 per agent per month and includes managed infrastructure, daily backups, uptime guarantees, and email/phone support, with a free trial available.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c6e21c1b-c4e0-486b-8501-88c1bbe7830a', $q$Who maintains osTicket?$q$, $q$osTicket is maintained by Enhancesoft, a software company headquartered in Alexandria, Louisiana, with an additional office in Eldoret, Kenya.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c6e21c1b-c4e0-486b-8501-88c1bbe7830a', $q$How long has osTicket been around?$q$, $q$osTicket has been in continuous development since 2003, making it one of the longest-running open-source help desk ticketing systems still actively maintained.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c6e21c1b-c4e0-486b-8501-88c1bbe7830a', $q$Can osTicket convert emails into tickets?$q$, $q$Yes, osTicket supports multi-channel ticket intake, automatically converting emails, web form submissions, and API requests into trackable support tickets.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c6e21c1b-c4e0-486b-8501-88c1bbe7830a', $q$What is the difference between osTicket and SupportSystem?$q$, $q$SupportSystem is Enhancesoft's separately branded, fully managed cloud version of osTicket, built on the same underlying codebase but delivered as a managed service rather than self-hosted software.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c6e21c1b-c4e0-486b-8501-88c1bbe7830a', $q$What are alternatives to osTicket?$q$, $q$Common alternatives include Zendesk, Freshdesk, Zammad, and OTRS/OTOBO, though osTicket differentiates itself with a genuinely free, unlimited self-hosted edition.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c6e21c1b-c4e0-486b-8501-88c1bbe7830a', $q$Small business customer support$q$, $q$Small businesses run the free self-hosted edition of osTicket to manage customer support tickets without paying per-agent SaaS fees.$q$, $q$Small and medium-sized businesses$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c6e21c1b-c4e0-486b-8501-88c1bbe7830a', $q$IT help desk ticketing$q$, $q$Internal IT teams use osTicket's routing, SLA, and department management features to track and resolve employee support requests.$q$, $q$Internal IT support teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c6e21c1b-c4e0-486b-8501-88c1bbe7830a', $q$Nonprofit and budget-constrained support operations$q$, $q$Nonprofit organizations rely on osTicket's free self-hosted edition to run a professional support desk on a limited budget.$q$, $q$Nonprofit and budget-conscious organizations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c6e21c1b-c4e0-486b-8501-88c1bbe7830a', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Self-hosted deployment","Email, web, and API ticket intake","SLA and routing rules","Customer self-service portal","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c6e21c1b-c4e0-486b-8501-88c1bbe7830a', $q$Cloud-Hosted$q$, $q$From $12/agent/month$q$, $q$Monthly$q$, NULL, $q$["Managed infrastructure","Daily backups","Uptime guarantee","Email and phone support","Free walk-through onboarding"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c6e21c1b-c4e0-486b-8501-88c1bbe7830a', $q$Enterprise / Virtual Appliance$q$, $q$Custom$q$, $q$Annual$q$, NULL, $q$["All Cloud-Hosted features","Full customization","Dedicated infrastructure options"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c6e21c1b-c4e0-486b-8501-88c1bbe7830a', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$osTicket is an open-source customer support ticketing system that has been actively developed since 2003, making it one of the most established open-source help desk platforms available today. It is maintained by Enhancesoft, a software company based in Alexandria, Louisiana.$q$, $q$The platform is available as a completely free, self-hosted, GPL-licensed edition, as well as paid Cloud-Hosted and Enterprise tiers for organizations that want managed infrastructure and additional support without giving up the underlying osTicket codebase.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c6e21c1b-c4e0-486b-8501-88c1bbe7830a', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$osTicket converts emails, web forms, and API submissions into trackable support tickets, with customizable filters and routing rules that direct tickets to the right department or agent automatically. SLA and business-hours management help teams enforce response-time policies.$q$, $q$The platform also includes a customer self-service portal with knowledge base articles, configurable help topics and custom forms, and department- and agent-level management, giving support teams the core building blocks of a full help desk without a mandatory subscription.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c6e21c1b-c4e0-486b-8501-88c1bbe7830a', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The self-hosted, open-source edition of osTicket is entirely free to download and run, with community-only support and no artificial limits on the number of agents.$q$, $q$The Cloud-Hosted plan starts at $12 per agent per month and includes managed infrastructure, daily backups, uptime guarantees, and email/phone support, while the Enterprise/Virtual Appliance tier offers custom pricing for organizations needing full customization alongside managed hosting.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c6e21c1b-c4e0-486b-8501-88c1bbe7830a', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c6e21c1b-c4e0-486b-8501-88c1bbe7830a', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7ff507f8-cdb5-4501-a01f-b42875d7b2a8', $q$Ticket management with SLAs$q$, $q$Full ticket lifecycle tracking with service level agreement and escalation management.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7ff507f8-cdb5-4501-a01f-b42875d7b2a8', $q$AI ticket classification$q$, $q$Machine learning plugin that automatically pre-sorts incoming tickets by category and priority.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7ff507f8-cdb5-4501-a01f-b42875d7b2a8', $q$Generic Agent automation$q$, $q$Rule-based automation engine for triggering actions, templates, and auto-responses on tickets.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7ff507f8-cdb5-4501-a01f-b42875d7b2a8', $q$Knowledge base and self-service portal$q$, $q$Customer-facing portal with searchable knowledge base articles to deflect routine tickets.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7ff507f8-cdb5-4501-a01f-b42875d7b2a8', $q$Process management workflows$q$, $q$Configurable business process workflows for structured, multi-step ticket handling.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7ff507f8-cdb5-4501-a01f-b42875d7b2a8', $q$Docker-based deployment$q$, $q$Containerized deployment simplifies self-hosting and upgrades.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7ff507f8-cdb5-4501-a01f-b42875d7b2a8', $q$Migration tooling$q$, $q$Built-in tools for migrating from OTRS 7, OTRS Community Edition, and Znuny.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7ff507f8-cdb5-4501-a01f-b42875d7b2a8', $q$Core software is fully free with no per-agent licensing costs and unlimited agents$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7ff507f8-cdb5-4501-a01f-b42875d7b2a8', $q$GPL v3 license guarantees the codebase stays fully open source$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7ff507f8-cdb5-4501-a01f-b42875d7b2a8', $q$AI-powered ticket classification is a differentiated feature versus many open-source competitors$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7ff507f8-cdb5-4501-a01f-b42875d7b2a8', $q$Built by a team with direct lineage to the original OTRS engineering organization$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7ff507f8-cdb5-4501-a01f-b42875d7b2a8', $q$Active, independent development separate from the now EasyVista-owned OTRS AG$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7ff507f8-cdb5-4501-a01f-b42875d7b2a8', $q$Migration tooling eases transition from discontinued OTRS Community Edition or Znuny$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7ff507f8-cdb5-4501-a01f-b42875d7b2a8', $q$Commercial support, hosting, and consulting pricing is not publicly listed and requires a custom quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7ff507f8-cdb5-4501-a01f-b42875d7b2a8', $q$Smaller company (Rother OSS) than larger commercial ITSM vendors$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7ff507f8-cdb5-4501-a01f-b42875d7b2a8', $q$Self-hosting requires familiarity with Perl and Docker-based deployment$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7ff507f8-cdb5-4501-a01f-b42875d7b2a8', $q$User interface carries over some of the dated design inherited from the original OTRS codebase$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7ff507f8-cdb5-4501-a01f-b42875d7b2a8', $q$Enterprise-grade support and advanced customization typically require paid consulting engagements$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7ff507f8-cdb5-4501-a01f-b42875d7b2a8', $q$Is OTOBO really free?$q$, $q$Yes. OTOBO's core software is free and open source under the GPL v3 license, with unlimited agents and no per-agent licensing fees when self-hosted. Paid options exist only for optional professional services like consulting, hosting, and support.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7ff507f8-cdb5-4501-a01f-b42875d7b2a8', $q$Who develops OTOBO?$q$, $q$OTOBO is developed and commercially supported by Rother OSS GmbH, a German software company headquartered in Leiblfing, Germany, founded by Stefan Rother, who was previously OTRS GmbH's first employee.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7ff507f8-cdb5-4501-a01f-b42875d7b2a8', $q$How is OTOBO different from OTRS?$q$, $q$OTOBO is a community fork of OTRS Community Edition created in 2019 to remain fully free and open source under GPL v3, while OTRS itself is now a commercial product from OTRS AG (majority-owned by EasyVista) with proprietary Business and Enterprise editions.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7ff507f8-cdb5-4501-a01f-b42875d7b2a8', $q$Can I migrate from OTRS to OTOBO?$q$, $q$Yes, OTOBO includes built-in migration tooling to help organizations move from OTRS 7, the discontinued OTRS Community Edition, and Znuny.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7ff507f8-cdb5-4501-a01f-b42875d7b2a8', $q$Does OTOBO support AI ticket classification?$q$, $q$Yes, OTOBO offers an AI-powered ticket classification plugin that uses machine learning to automatically pre-sort incoming tickets by category and priority.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7ff507f8-cdb5-4501-a01f-b42875d7b2a8', $q$How much does OTOBO support cost?$q$, $q$OTOBO's core software is free, and professional support, hosting, and consulting from Rother OSS are priced on a custom, quote-based basis rather than published per-agent rates.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7ff507f8-cdb5-4501-a01f-b42875d7b2a8', $q$What license is OTOBO released under?$q$, $q$OTOBO is licensed under the GNU General Public License version 3 (GPL v3).$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7ff507f8-cdb5-4501-a01f-b42875d7b2a8', $q$ITSM for organizations migrating off OTRS Community Edition$q$, $q$Organizations that previously ran the discontinued OTRS Community Edition migrate to OTOBO to keep a free, actively maintained ticketing platform.$q$, $q$IT service management teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7ff507f8-cdb5-4501-a01f-b42875d7b2a8', $q$MSP help desk operations$q$, $q$Managed service providers use OTOBO's unlimited-agent free model to run client support desks without per-agent licensing costs.$q$, $q$Managed service providers (MSPs)$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7ff507f8-cdb5-4501-a01f-b42875d7b2a8', $q$AI-assisted ticket triage$q$, $q$Support teams use OTOBO's AI classification plugin to automatically pre-sort and prioritize high ticket volumes.$q$, $q$IT and customer support teams handling high ticket volume$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7ff507f8-cdb5-4501-a01f-b42875d7b2a8', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Unlimited agents","Full ticketing and SLA management","AI ticket classification plugin","Self-hosted via Docker","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7ff507f8-cdb5-4501-a01f-b42875d7b2a8', $q$Professional Support$q$, $q$Custom quote$q$, $q$Contract-based$q$, NULL, $q$["Consulting and implementation","Managed hosting options","Training","Technical support","Custom feature development"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7ff507f8-cdb5-4501-a01f-b42875d7b2a8', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$OTOBO is an open-source IT service management and ticketing platform created in 2019 as a fork of OTRS Community Edition, built to preserve a fully free, GPLv3-licensed alternative after OTRS AG moved away from supporting a fully open community edition. It is developed and commercially backed by Rother OSS GmbH, a German company founded by Stefan Rother, OTRS GmbH's first employee.$q$, $q$OTOBO covers classic IT service desk functionality, including ticket management, SLAs, and self-service portals, while adding modern capabilities like Docker-based deployment, migration tooling from OTRS and Znuny, and an AI-powered ticket classification plugin.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7ff507f8-cdb5-4501-a01f-b42875d7b2a8', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$OTOBO's core ticketing engine handles ticket recording, SLA and escalation management, department routing, and a customer-facing self-service portal with a knowledge base. Automation is handled through the Generic Agent engine, ticket templates, and auto-responses.$q$, $q$A standout feature is OTOBO's AI ticket classification plugin, which uses machine learning to automatically pre-sort incoming tickets by category and priority, reducing manual triage work for support teams.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7ff507f8-cdb5-4501-a01f-b42875d7b2a8', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$OTOBO's core software is completely free to self-host under the GPL v3 license, with unlimited agents and no per-agent licensing fees, making it one of the more cost-effective open-source ITSM platforms available.$q$, $q$Rother OSS monetizes through professional services rather than software licensing, offering consulting, training, managed hosting, technical support, and custom development on a custom, quote-based pricing basis.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7ff507f8-cdb5-4501-a01f-b42875d7b2a8', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('47b3f39e-f481-4d52-be50-11d497bacb7b', $q$Ticket and case management$q$, $q$Enterprise-grade ticketing with case tracking across multiple communication channels.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('47b3f39e-f481-4d52-be50-11d497bacb7b', $q$IT service management (ITSM)$q$, $q$Dedicated ITSM module for incident, problem, and change management workflows.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('47b3f39e-f481-4d52-be50-11d497bacb7b', $q$Security incident response and SOAR$q$, $q$Security orchestration, automation, and response capabilities for security operations teams.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('47b3f39e-f481-4d52-be50-11d497bacb7b', $q$SLA and escalation management$q$, $q$Configurable service level agreements with automated escalation rules.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('47b3f39e-f481-4d52-be50-11d497bacb7b', $q$Reporting and analytics dashboards$q$, $q$Built-in dashboards for tracking ticket volume, response times, and team performance.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('47b3f39e-f481-4d52-be50-11d497bacb7b', $q$ISMS compliance tooling$q$, $q$Information security management system features aligned with standards like ISO 27001.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('47b3f39e-f481-4d52-be50-11d497bacb7b', $q$On-premise and managed cloud deployment$q$, $q$Flexible deployment options including on-premise installation and vendor-managed hosting.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('47b3f39e-f481-4d52-be50-11d497bacb7b', $q$Mature, enterprise-grade platform with over two decades of development history$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('47b3f39e-f481-4d52-be50-11d497bacb7b', $q$Strong depth in ITSM and SOAR functionality beyond basic ticketing$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('47b3f39e-f481-4d52-be50-11d497bacb7b', $q$Publicly traded parent company (OTRS AG) provides financial transparency and accountability$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('47b3f39e-f481-4d52-be50-11d497bacb7b', $q$International subsidiary network supports large, multi-region enterprise deployments$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('47b3f39e-f481-4d52-be50-11d497bacb7b', $q$ISMS/compliance tooling suited to regulated industries$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('47b3f39e-f481-4d52-be50-11d497bacb7b', $q$Formal vendor support contracts and SLAs available for enterprise customers$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('47b3f39e-f481-4d52-be50-11d497bacb7b', $q$Free Community Edition was discontinued in December 2020, removing the no-cost entry option$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('47b3f39e-f481-4d52-be50-11d497bacb7b', $q$Pricing is quote-based and can be costly at scale compared to open-source alternatives$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('47b3f39e-f481-4d52-be50-11d497bacb7b', $q$Steeper learning curve and implementation complexity than lightweight helpdesk tools$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('47b3f39e-f481-4d52-be50-11d497bacb7b', $q$Organizations must migrate to a paid edition or an open-source fork like OTOBO or Znuny$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('47b3f39e-f481-4d52-be50-11d497bacb7b', $q$Smaller open-source community today since the shift to a fully commercial model$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('47b3f39e-f481-4d52-be50-11d497bacb7b', $q$Is OTRS free to use?$q$, $q$No. OTRS AG discontinued the free Community Edition in December 2020, and OTRS is now sold exclusively as commercial software through Business and Enterprise editions.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('47b3f39e-f481-4d52-be50-11d497bacb7b', $q$How much does OTRS cost?$q$, $q$OTRS pricing is quote-based. Third-party estimates put the Business Edition starting around $49 per agent per month, with total costs commonly estimated between $25 and $100 per agent per month depending on modules, and Enterprise Edition pricing fully custom.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('47b3f39e-f481-4d52-be50-11d497bacb7b', $q$What is the difference between OTRS and OTOBO?$q$, $q$OTRS is the commercial, proprietary-licensed original product from OTRS AG in Germany. OTOBO is an independent open-source fork of the former OTRS Community Edition, created in 2019 by Rother OSS GmbH, and remains free and GPL v3 licensed.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('47b3f39e-f481-4d52-be50-11d497bacb7b', $q$When was OTRS founded?$q$, $q$The OTRS project began in 2001, created by developer Martin Edenhofer, with the commercial company OTRS GmbH founded in 2003 and later restructured as the publicly traded OTRS AG in 2007.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('47b3f39e-f481-4d52-be50-11d497bacb7b', $q$Where is OTRS AG headquartered?$q$, $q$OTRS AG is headquartered in Oberursel, Germany, with subsidiaries in the United States, Mexico, Singapore, Hong Kong, Brazil, and Hungary.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('47b3f39e-f481-4d52-be50-11d497bacb7b', $q$Who owns OTRS AG today?$q$, $q$In December 2024, French enterprise service management vendor EasyVista acquired a majority stake in OTRS AG.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('47b3f39e-f481-4d52-be50-11d497bacb7b', $q$What are alternatives to OTRS?$q$, $q$Alternatives include ServiceNow, Freshservice, Jira Service Management, and the open-source forks OTOBO and Znuny, which continue development of the discontinued OTRS Community Edition codebase.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('47b3f39e-f481-4d52-be50-11d497bacb7b', $q$Enterprise IT service desk$q$, $q$Large enterprises use OTRS's ITSM module to manage incident, problem, and change management workflows at scale.$q$, $q$Enterprise IT service management teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('47b3f39e-f481-4d52-be50-11d497bacb7b', $q$Security operations and incident response$q$, $q$Security operations centers use OTRS's SOAR capabilities to coordinate and automate incident response processes.$q$, $q$Security operations and incident response teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('47b3f39e-f481-4d52-be50-11d497bacb7b', $q$Regulated industry compliance ticketing$q$, $q$Organizations in regulated industries use OTRS's ISMS tooling alongside ticketing to maintain ISO 27001-aligned documentation.$q$, $q$Regulated enterprises requiring compliance documentation$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('47b3f39e-f481-4d52-be50-11d497bacb7b', $q$Business Edition$q$, $q$From ~$49/agent/month$q$, $q$Monthly or annual$q$, NULL, $q$["Ticket and case management","SLA and escalation management","Reporting dashboards","Standard support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('47b3f39e-f481-4d52-be50-11d497bacb7b', $q$Enterprise Edition$q$, $q$Custom (contact sales)$q$, $q$Annual$q$, NULL, $q$["Full ITSM module","Security incident response and SOAR","ISMS compliance tooling","Dedicated enterprise support"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('47b3f39e-f481-4d52-be50-11d497bacb7b', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$OTRS began in 2001 as an open-source help desk ticketing project created by developer Martin Edenhofer, with the commercial company OTRS GmbH founded in 2003 and later becoming the publicly traded OTRS AG, headquartered in Oberursel, Germany. OTRS AG operates subsidiaries in the United States, Mexico, Singapore, Hong Kong, Brazil, and Hungary.$q$, $q$The company progressively moved from a free open-source model toward a commercial one, culminating in the discontinuation of its free Community Edition in December 2020. That decision prompted the community to create open-source forks, most notably OTOBO and Znuny, to continue a free version of the codebase.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('47b3f39e-f481-4d52-be50-11d497bacb7b', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$OTRS today is positioned as an enterprise service management platform covering ticket and case management, IT service management (ITSM), and security incident response with SOAR (security orchestration, automation and response) capabilities, alongside SLA and escalation management and reporting dashboards.$q$, $q$The platform also includes information security management system (ISMS) tooling aligned with standards like ISO 27001, supporting regulated organizations that need formal compliance documentation alongside their service desk operations.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('47b3f39e-f481-4d52-be50-11d497bacb7b', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$OTRS pricing is quote-based rather than published outright, with the Business Edition estimated to start around $49 per agent per month according to third-party sources, and total costs for complex deployments estimated in the $25 to $100 per agent per month range depending on selected modules.$q$, $q$The Enterprise Edition, aimed at large organizations with complex requirements, is priced entirely on a custom quote basis. There is no longer a free Community Edition available, as OTRS AG discontinued it in December 2020.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c4d14d8f-274a-43ad-92f6-8e61529bc76c', $q$Client-side AES-256 encryption$q$, $q$Secrets are encrypted in the browser using symmetric 256-bit AES encryption before being sent to the server.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c4d14d8f-274a-43ad-92f6-8e61529bc76c', $q$Self-destructing secrets$q$, $q$Secrets are permanently deleted immediately after their first successful read.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c4d14d8f-274a-43ad-92f6-8e61529bc76c', $q$Server-blind password handling$q$, $q$The decryption password is embedded only in the URL fragment, which browsers never transmit to the server.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c4d14d8f-274a-43ad-92f6-8e61529bc76c', $q$Command-line interface$q$, $q$A CLI tool allows scripted creation and retrieval of secrets, useful for automation workflows.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c4d14d8f-274a-43ad-92f6-8e61529bc76c', $q$Configurable expiry and file attachments$q$, $q$Secrets can be set to expire after a defined time window and can include attached files.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c4d14d8f-274a-43ad-92f6-8e61529bc76c', $q$Pluggable storage backends$q$, $q$Supports in-memory storage for lightweight setups or Redis for more durable, production-grade deployments.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c4d14d8f-274a-43ad-92f6-8e61529bc76c', $q$Docker-based self-hosting$q$, $q$Distributed as a Docker image and standalone binaries for straightforward self-hosted deployment.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c4d14d8f-274a-43ad-92f6-8e61529bc76c', $q$Completely free and open source under the Apache 2.0 license$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c4d14d8f-274a-43ad-92f6-8e61529bc76c', $q$Strong client-side encryption model means the server never sees plaintext secrets$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c4d14d8f-274a-43ad-92f6-8e61529bc76c', $q$Self-destructing links prevent secrets from being retrieved more than once$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c4d14d8f-274a-43ad-92f6-8e61529bc76c', $q$Lightweight Docker-based self-hosting with minimal setup$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c4d14d8f-274a-43ad-92f6-8e61529bc76c', $q$Command-line interface supports scripted, automated secret sharing$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c4d14d8f-274a-43ad-92f6-8e61529bc76c', $q$Public ots.fyi demo instance is usable without registration for quick one-off sharing$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c4d14d8f-274a-43ad-92f6-8e61529bc76c', $q$No official managed or enterprise hosting option since there is no company behind the project$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c4d14d8f-274a-43ad-92f6-8e61529bc76c', $q$Maintained by an individual developer rather than a dedicated team, which can affect long-term support guarantees$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c4d14d8f-274a-43ad-92f6-8e61529bc76c', $q$Lacks enterprise features like SSO, audit logs, or access controls found in commercial secret-management tools$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c4d14d8f-274a-43ad-92f6-8e61529bc76c', $q$Minimal, utilitarian interface compared to polished commercial secret-sharing products$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c4d14d8f-274a-43ad-92f6-8e61529bc76c', $q$Self-hosting requires basic server and Docker administration knowledge$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c4d14d8f-274a-43ad-92f6-8e61529bc76c', $q$Is OTS (ots.fyi) free to use?$q$, $q$Yes, OTS is completely free and open source. The public demo at ots.fyi can be used directly at no cost, and the underlying software can be self-hosted for free as well.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c4d14d8f-274a-43ad-92f6-8e61529bc76c', $q$Who maintains OTS?$q$, $q$OTS is developed and maintained by an independent open-source developer known as Luzifer, with the source code hosted on GitHub under the Apache 2.0 license, rather than by a commercial company.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c4d14d8f-274a-43ad-92f6-8e61529bc76c', $q$How does OTS keep secrets secure?$q$, $q$OTS encrypts secrets with symmetric 256-bit AES encryption directly in the browser before sending them to the server, and the decryption password is embedded only in the URL fragment, which is never transmitted to the server, so the server only handles ciphertext.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c4d14d8f-274a-43ad-92f6-8e61529bc76c', $q$What happens after a secret is read on OTS?$q$, $q$The secret is immediately and permanently deleted from storage after its first successful read, preventing it from being retrieved again.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c4d14d8f-274a-43ad-92f6-8e61529bc76c', $q$Can I self-host OTS instead of using ots.fyi?$q$, $q$Yes, OTS is distributed as a Docker image and standalone binaries, with support for in-memory or Redis storage backends, making it straightforward to self-host on your own infrastructure.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c4d14d8f-274a-43ad-92f6-8e61529bc76c', $q$Does OTS have a command-line tool?$q$, $q$Yes, OTS includes a command-line interface for creating and retrieving secrets programmatically, with support for configurable expiry times and file attachments.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c4d14d8f-274a-43ad-92f6-8e61529bc76c', $q$What are alternatives to OTS?$q$, $q$Alternatives include Onetime Secret, PrivateBin, and Yopass, all of which offer similar self-hosted or hosted one-time secret sharing with client-side encryption.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c4d14d8f-274a-43ad-92f6-8e61529bc76c', $q$Secure credential sharing between developers$q$, $q$Developers use OTS to share passwords, API keys, and tokens with teammates as self-destructing links instead of pasting them into chat or email.$q$, $q$Developers and DevOps engineers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c4d14d8f-274a-43ad-92f6-8e61529bc76c', $q$IT password delivery to end users$q$, $q$IT teams send temporary account passwords to employees or clients as one-time links that disappear after being viewed.$q$, $q$IT support and helpdesk teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c4d14d8f-274a-43ad-92f6-8e61529bc76c', $q$Privacy-conscious personal secret sharing$q$, $q$Individuals use the public ots.fyi instance or a self-hosted copy to share sensitive personal information without leaving a persistent copy in email or chat history.$q$, $q$Privacy-conscious individuals$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c4d14d8f-274a-43ad-92f6-8e61529bc76c', $q$Open Source (Self-Hosted or ots.fyi)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Client-side AES-256 encryption","Self-destructing one-time links","Command-line interface","Configurable expiry and file attachments","Docker-based self-hosting"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c4d14d8f-274a-43ad-92f6-8e61529bc76c', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$OTS, or One Time Secrets, is a free, open-source tool for sharing sensitive text and files as self-destructing, one-time-use links. The public demo instance runs at ots.fyi, and the underlying project is developed and maintained by independent open-source developer Luzifer under the Apache 2.0 license.$q$, $q$Unlike commercial secret-sharing products, OTS has no company or funding behind it; it is a lightweight, community-maintained tool intended to be self-hosted by individuals, development teams, or IT departments who want full control over how sensitive text is shared and stored.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c4d14d8f-274a-43ad-92f6-8e61529bc76c', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$OTS encrypts secrets with symmetric 256-bit AES encryption directly in the browser before the data is ever sent to the server, and the decryption password lives only in the URL fragment, which browsers do not transmit to the server. This means the server only ever stores and handles ciphertext.$q$, $q$Secrets are permanently deleted immediately after their first read, preventing later retrieval even by someone with direct server access. A companion command-line interface allows scripted creation and retrieval of secrets with configurable expiry times and file attachments, and the project supports both in-memory and Redis storage backends for self-hosted deployments.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c4d14d8f-274a-43ad-92f6-8e61529bc76c', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$OTS is entirely free and open source, with no company, subscription plans, or paid tiers behind it. Self-hosters only bear the cost of running their own server or container, such as via the official Docker image.$q$, $q$The public ots.fyi instance is also free to use directly for occasional secret sharing without any registration or account, making it accessible without self-hosting for lighter use cases.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c4d14d8f-274a-43ad-92f6-8e61529bc76c', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c4d14d8f-274a-43ad-92f6-8e61529bc76c', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
